return new Promise((resolve) => {
  const checkExistence = setInterval(() => {
    let blockElements = [];
    let frame = document.querySelector('iframe.phlearn-iframe.checkout, iframe#wcp-checkout-iframe');

    if (frame !== null) {
      try {
        let iframeDocument = frame.contentWindow?.document || frame.contentDocument;
        blockElements = iframeDocument?.querySelectorAll('.blockUI, .wc-blocks-components-button--loading, .wc-block-components-spinner, .wc-block-components-checkout-place-order-button--loading') || [];
      } catch (error) {
        console.warn('Cross-origin iframe detected, skipping iframe check.');
      }
    } else {
      blockElements = document.querySelectorAll('.blockUI, .wc-blocks-components-button--loading, .wc-block-components-spinner, .wc-block-components-checkout-place-order-button--loading');
    }

    if (blockElements.length === 0) {
      clearInterval(checkExistence);
      console.log("✅ BlockUi unblocked!");
      resolve(true);
    } else {
      console.log("⏳ Waiting for  blockUI to unblock...");
    }
  }, 2000);
})
